    30→#include "json.h"
    31→#include "utils.h"
    32→
    33→#ifdef _MSC_VER
    34→#ifndef _CRT_SECURE_NO_WARNINGS
    35→#define _CRT_SECURE_NO_WARNINGS
    36→#endif
    37→#endif
    38→
    39→#ifdef __cplusplus
    40→const struct _json_value json_value_none; /* zero-d by ctor */
    41→#else
    42→const struct _json_value json_value_none = { NULL, 0, { 0 }, { NULL } };
    43→#endif
    44→
    45→#include <stdio.h>
    46→#include <string.h>
    47→#include <ctype.h>
    48→#include <math.h>
    49→
    50→typedef unsigned short json_uchar;
    51→
    52→static unsigned char
    53→hex_value(json_char c)
    54→{
    55→    if (isdigit((uint8_t)c)) {
    56→        return c - '0';
    57→    }
    58→
    59→    switch (c) {
    60→    case 'a':
    61→    case 'A':
    62→        return 0x0A;
    63→    case 'b':
    64→    case 'B':
    65→        return 0x0B;
    66→    case 'c':
    67→    case 'C':
    68→        return 0x0C;
    69→    case 'd':
    70→    case 'D':
    71→        return 0x0D;
    72→    case 'e':
    73→    case 'E':
    74→        return 0x0E;
    75→    case 'f':
    76→    case 'F':
    77→        return 0x0F;
    78→    default:
    79→        return 0xFF;
    80→    }
    81→}
    82→
    83→typedef struct {
    84→    unsigned long used_memory;
    85→
    86→    unsigned int uint_max;
    87→    unsigned long ulong_max;
    88→
    89→    json_settings settings;
    90→    int first_pass;
    91→} json_state;
    92→
    93→static void *
    94→default_alloc(size_t size, int zero, void *user_data)
    95→{
    96→    return zero ? calloc(1, size) : ss_malloc(size);
    97→}
    98→
    99→static void
   100→default_free(void *ptr, void *user_data)
   101→{
   102→    ss_free(ptr);
   103→}
   104→
   105→static void *
   106→json_alloc(json_state *state, unsigned long size, int zero)
   107→{
   108→    if ((state->ulong_max - state->used_memory) < size) {
   109→        return 0;
   110→    }
   111→
   112→    if (state->settings.max_memory
   113→        && (state->used_memory += size) > state->settings.max_memory) {
   114→        return 0;
   115→    }
   116→
   117→    return state->settings.mem_alloc(size, zero, state->settings.user_data);
   118→}
   119→
   120→static int
   121→new_value(json_state *state, json_value **top, json_value **root,
   122→          json_value **alloc, json_type type)
   123→{
   124→    json_value *value;
   125→    int values_size;
   126→
   127→    if (!state->first_pass) {
   128→        value  = *top = *alloc;
   129→        *alloc = (*alloc)->_reserved.next_alloc;
   130→
   131→        if (!*root) {
   132→            *root = value;
   133→        }
   134→
   135→        switch (value->type) {
   136→        case json_array:
   137→
   138→            if (!(value->u.array.values = (json_value **)json_alloc
   139→                                              (state, value->u.array.length *
   140→                                              sizeof(json_value *), 0))) {
   141→                return 0;
   142→            }
   143→
   144→            value->u.array.length = 0;
   145→            break;
   146→
   147→        case json_object:
   148→
   149→            values_size = sizeof(*value->u.object.values) *
   150→                          value->u.object.length;
   151→
   152→            if (!((*(void **)&value->u.object.values) = json_alloc
   153→                                                            (state,
   154→                                                            values_size +
   155→                                                            ((size_t)value->u.
   156→                                                             object.values),
   157→                                                            0))) {
   158→                return 0;
   159→            }
   160→
   161→            value->_reserved.object_mem = (*(char **)&value->u.object.values) +
   162→                                          values_size;
   163→
   164→            value->u.object.length = 0;
   165→            break;
   166→
   167→        case json_string:
   168→
   169→            if (!(value->u.string.ptr = (json_char *)json_alloc
   170→                                            (state,
   171→                                            (value->u.string.length +
   172→                                             1) * sizeof(json_char), 0))) {
   173→                return 0;
   174→            }
   175→
   176→            value->u.string.length = 0;
   177→            break;
   178→
   179→        default:
   180→            break;
   181→        }
   182→
   183→        return 1;
   184→    }
   185→
   186→    value = (json_value *)json_alloc(state, sizeof(json_value), 1);
   187→
   188→    if (!value) {
   189→        return 0;
   190→    }
   191→
   192→    if (!*root) {
   193→        *root = value;
   194→    }
   195→
   196→    value->type   = type;
   197→    value->parent = *top;
   198→
   199→    if (*alloc) {
   200→        (*alloc)->_reserved.next_alloc = value;
   201→    }
   202→
   203→    *alloc = *top = value;
   204→
   205→    return 1;
   206→}
   207→
   208→#define e_off \
   209→    ((int)(i - cur_line_begin))
   210→
   211→#define whitespace                          \
   212→case '\n': \
   213→    ++cur_line; cur_line_begin = i; \
   214→case ' ': \
   215→case '\t': \
   216→case '\r'
   217→
   218→#define string_add(b)                                         \
   219→    do { if (!state.first_pass) { string[string_length] = b; \
   220→         } ++string_length; } while (0)
   221→
   222→static const long
   223→    flag_next           = 1 << 0,
   224→    flag_reproc         = 1 << 1,
   225→    flag_need_comma     = 1 << 2,
   226→    flag_seek_value     = 1 << 3,
   227→    flag_escaped        = 1 << 4,
   228→    flag_string         = 1 << 5,
   229→    flag_need_colon     = 1 << 6,
   230→    flag_done           = 1 << 7,
   231→    flag_num_negative   = 1 << 8,
   232→    flag_num_zero       = 1 << 9,
   233→    flag_num_e          = 1 << 10,
   234→    flag_num_e_got_sign = 1 << 11,
   235→    flag_num_e_negative = 1 << 12,
   236→    flag_line_comment   = 1 << 13,
   237→    flag_block_comment  = 1 << 14;
   238→
   239→json_value *
   240→json_parse_ex(json_settings *settings,
   241→              const json_char *json,
   242→              size_t length,
   243→              char *error_buf)
   244→{
   245→    json_char error[json_error_max];
   246→    int cur_line;
   247→    const json_char *cur_line_begin, *i, *end;
   248→    json_value *top, *root, *alloc = 0;
   249→    json_state state = { 0UL, 0U, 0UL, { 0UL, 0, NULL, NULL, NULL }, 0 };
   250→    long flags;
   251→    long num_digits = 0, num_e = 0;
   252→    json_int_t num_fraction = 0;
   253→
   254→    /* Skip UTF-8 BOM
   255→     */
   256→    if (length >= 3 && ((unsigned char)json[0]) == 0xEF
   257→        && ((unsigned char)json[1]) == 0xBB
   258→        && ((unsigned char)json[2]) == 0xBF) {
   259→        json   += 3;
   260→        length -= 3;
   261→    }
   262→
   263→    error[0] = '\0';
   264→    end      = (json + length);
   265→
   266→    memcpy(&state.settings, settings, sizeof(json_settings));
   267→
   268→    if (!state.settings.mem_alloc) {
   269→        state.settings.mem_alloc = default_alloc;
   270→    }
   271→
   272→    if (!state.settings.mem_free) {
   273→        state.settings.mem_free = default_free;
   274→    }
   275→
   276→    memset(&state.uint_max, 0xFF, sizeof(state.uint_max));
   277→    memset(&state.ulong_max, 0xFF, sizeof(state.ulong_max));
   278→
   279→    state.uint_max  -= 8; /* limit of how much can be added before next check */
   280→    state.ulong_max -= 8;
   281→
   282→    for (state.first_pass = 1; state.first_pass >= 0; --state.first_pass) {
   283→        json_uchar uchar;
   284→        unsigned char uc_b1, uc_b2, uc_b3, uc_b4;
   285→        json_char *string          = 0;
   286→        unsigned int string_length = 0;
   287→
   288→        top   = root = 0;
   289→        flags = flag_seek_value;
   290→
   291→        cur_line       = 1;
   292→        cur_line_begin = json;
   293→
   294→        for (i = json;; ++i) {
   295→            json_char b = (i == end ? 0 : *i);
   296→
   297→            if (flags & flag_string) {
   298→                if (!b) {
   299→                    sprintf(error, "Unexpected EOF in string (at %d:%d)",
   300→                            cur_line, e_off);
   301→                    goto e_failed;
   302→                }
   303→
   304→                if (string_length > state.uint_max) {
   305→                    goto e_overflow;
   306→                }
   307→
   308→                if (flags & flag_escaped) {
   309→                    flags &= ~flag_escaped;
   310→
   311→                    switch (b) {
   312→                    case 'b':
   313→                        string_add('\b');
   314→                        break;
   315→                    case 'f':
   316→                        string_add('\f');
   317→                        break;
   318→                    case 'n':
   319→                        string_add('\n');
   320→                        break;
   321→                    case 'r':
   322→                        string_add('\r');
   323→                        break;
   324→                    case 't':
   325→                        string_add('\t');
   326→                        break;
   327→                    case 'u':
   328→
   329→                        if (end - i < 4 ||
   330→                            (uc_b1 = hex_value(*++i)) == 0xFF ||
   331→                            (uc_b2 = hex_value(*++i)) == 0xFF
   332→                            || (uc_b3 = hex_value(*++i)) == 0xFF ||
   333→                            (uc_b4 = hex_value(*++i)) == 0xFF) {
   334→                            sprintf(error,
   335→                                    "Invalid character value `%c` (at %d:%d)",
   336→                                    b, cur_line, e_off);
   337→                            goto e_failed;
   338→                        }
   339→
   340→                        uc_b1 = uc_b1 * 16 + uc_b2;
   341→                        uc_b2 = uc_b3 * 16 + uc_b4;
   342→
   343→                        uchar = ((json_char)uc_b1) * 256 + uc_b2;
   344→
   345→                        if (sizeof(json_char) >= sizeof(json_uchar) ||
   346→                            (uc_b1 == 0 && uc_b2 <= 0x7F)) {
   347→                            string_add((json_char)uchar);
   348→                            break;
   349→                        }
   350→
   351→                        if (uchar <= 0x7FF) {
   352→                            if (state.first_pass) {
   353→                                string_length += 2;
   354→                            } else {
   355→                                string[string_length++] = 0xC0 |
   356→                                                          ((uc_b2 &
   357→                                                            0xC0) >>
   358→                                                           6) |
   359→                                                          ((uc_b1 & 0x7) << 2);
   360→                                string[string_length++] = 0x80 |
   361→                                                          (uc_b2 & 0x3F);
   362→                            }
   363→
   364→                            break;
   365→                        }
   366→
   367→                        if (state.first_pass) {
   368→                            string_length += 3;
   369→                        } else {
   370→                            string[string_length++] = 0xE0 |
   371→                                                      ((uc_b1 & 0xF0) >> 4);
   372→                            string[string_length++] = 0x80 |
   373→                                                      ((uc_b1 &
   374→                                                        0xF) <<
   375→                                                       2) |
   376→                                                      ((uc_b2 & 0xC0) >> 6);
   377→                            string[string_length++] = 0x80 | (uc_b2 & 0x3F);
   378→                        }
   379→
   380→                        break;
   381→
   382→                    default:
   383→                        string_add(b);
   384→                    }
   385→
   386→                    continue;
   387→                }
   388→
   389→                if (b == '\\') {
   390→                    flags |= flag_escaped;
   391→                    continue;
   392→                }
   393→
   394→                if (b == '"') {
   395→                    if (!state.first_pass) {
   396→                        string[string_length] = 0;
   397→                    }
   398→
   399→                    flags &= ~flag_string;
   400→                    string = 0;
   401→
   402→                    switch (top->type) {
   403→                    case json_string:
   404→
   405→                        top->u.string.length = string_length;
   406→                        flags               |= flag_next;
   407→
   408→                        break;
   409→
   410→                    case json_object:
   411→
   412→                        if (state.first_pass) {
   413→                            (*(json_char **)&top->u.object.values) +=
   414→                                string_length + 1;
   415→                        } else {
   416→                            top->u.object.values[top->u.object.length].name
   417→                                = (json_char *)top->_reserved.object_mem;
   418→
   419→                            top->u.object.values[top->u.object.length].
   420→                            name_length
   421→                                = string_length;
   422→
   423→                            (*(json_char **)&top->_reserved.object_mem) +=
   424→                                string_length + 1;
   425→                        }
   426→
   427→                        flags |= flag_seek_value | flag_need_colon;
   428→                        continue;
   429→
   430→                    default:
   431→                        break;
   432→                    }
   433→                } else {
   434→                    string_add(b);
   435→                    continue;
   436→                }
   437→            }
   438→
   439→            if (state.settings.settings & json_enable_comments) {
   440→                if (flags & (flag_line_comment | flag_block_comment)) {
   441→                    if (flags & flag_line_comment) {
   442→                        if (b == '\r' || b == '\n' || !b) {
   443→                            flags &= ~flag_line_comment;
   444→                            --i;   /* so null can be reproc'd */
   445→                        }
   446→
   447→                        continue;
   448→                    }
   449→
   450→                    if (flags & flag_block_comment) {
   451→                        if (!b) {
   452→                            sprintf(error,
   453→                                    "%d:%d: Unexpected EOF in block comment",
   454→                                    cur_line, e_off);
   455→                            goto e_failed;
   456→                        }
   457→
   458→                        if (b == '*' && i < (end - 1) && i[1] == '/') {
   459→                            flags &= ~flag_block_comment;
   460→                            ++i;   /* skip closing sequence */
   461→                        }
   462→
   463→                        continue;
   464→                    }
   465→                } else if (b == '/') {
   466→                    if (!(flags & (flag_seek_value | flag_done)) && top->type !=
   467→                        json_object) {
   468→                        sprintf(error, "%d:%d: Comment not allowed here",
   469→                                cur_line, e_off);
   470→                        goto e_failed;
   471→                    }
   472→
   473→                    if (++i == end) {
   474→                        sprintf(error, "%d:%d: EOF unexpected", cur_line,
   475→                                e_off);
   476→                        goto e_failed;
   477→                    }
   478→
   479→                    switch (b = *i) {
   480→                    case '/':
   481→                        flags |= flag_line_comment;
   482→                        continue;
   483→
   484→                    case '*':
   485→                        flags |= flag_block_comment;
   486→                        continue;
   487→
   488→                    default:
   489→                        sprintf(error,
   490→                                "%d:%d: Unexpected `%c` in comment opening sequence", cur_line, e_off,
   491→                                b);
   492→                        goto e_failed;
   493→                    }
   494→                }
   495→            }
   496→
   497→            if (flags & flag_done) {
   498→                if (!b) {
   499→                    break;
   500→                }
   501→
   502→                switch (b) {
   503→whitespace:
   504→                    continue;
   505→
   506→                default:
   507→                    sprintf(error, "%d:%d: Trailing garbage: `%c`", cur_line,
   508→                            e_off, b);
   509→                    goto e_failed;
   510→                }
   511→            }
   512→
   513→            if (flags & flag_seek_value) {
   514→                switch (b) {
   515→whitespace:
   516→                    continue;
   517→
   518→                case ']':
   519→
   520→                    if (top->type == json_array) {
   521→                        flags =
   522→                            (flags &
   523→                             ~(flag_need_comma | flag_seek_value)) | flag_next;
   524→                    } else {
   525→                        sprintf(error, "%d:%d: Unexpected ]", cur_line, e_off);
   526→                        goto e_failed;
   527→                    }
   528→
   529→                    break;
   530→
   531→                default:
   532→
   533→                    if (flags & flag_need_comma) {
   534→                        if (b == ',') {
   535→                            flags &= ~flag_need_comma;
   536→                            continue;
   537→                        } else {
   538→                            sprintf(error, "%d:%d: Expected , before %c",
   539→                                    cur_line, e_off, b);
   540→                            goto e_failed;
   541→                        }
   542→                    }
   543→
   544→                    if (flags & flag_need_colon) {
   545→                        if (b == ':') {
   546→                            flags &= ~flag_need_colon;
   547→                            continue;
   548→                        } else {
   549→                            sprintf(error, "%d:%d: Expected : before %c",
   550→                                    cur_line, e_off, b);
   551→                            goto e_failed;
   552→                        }
   553→                    }
   554→
   555→                    flags &= ~flag_seek_value;
   556→
   557→                    switch (b) {
   558→                    case '{':
   559→
   560→                        if (!new_value(&state, &top, &root, &alloc,
   561→                                       json_object)) {
   562→                            goto e_alloc_failure;
   563→                        }
   564→
   565→                        continue;
   566→
   567→                    case '[':
   568→
   569→                        if (!new_value(&state, &top, &root, &alloc,
   570→                                       json_array)) {
   571→                            goto e_alloc_failure;
   572→                        }
   573→
   574→                        flags |= flag_seek_value;
   575→                        continue;
   576→
   577→                    case '"':
   578→
   579→                        if (!new_value(&state, &top, &root, &alloc,
   580→                                       json_string)) {
   581→                            goto e_alloc_failure;
   582→                        }
   583→
   584→                        flags |= flag_string;
   585→
   586→                        string        = top->u.string.ptr;
   587→                        string_length = 0;
   588→
   589→                        continue;
   590→
   591→                    case 't':
   592→
   593→                        if ((end - i) < 3 || *(++i) != 'r' || *(++i) != 'u' ||
   594→                            *(++i) != 'e') {
   595→                            goto e_unknown_value;
   596→                        }
   597→
   598→                        if (!new_value(&state, &top, &root, &alloc,
   599→                                       json_boolean)) {
   600→                            goto e_alloc_failure;
   601→                        }
   602→
   603→                        top->u.boolean = 1;
   604→
   605→                        flags |= flag_next;
   606→                        break;
   607→
   608→                    case 'f':
   609→
   610→                        if ((end - i) < 4 || *(++i) != 'a' || *(++i) != 'l' ||
   611→                            *(++i) != 's' || *(++i) != 'e') {
   612→                            goto e_unknown_value;
   613→                        }
   614→
   615→                        if (!new_value(&state, &top, &root, &alloc,
   616→                                       json_boolean)) {
   617→                            goto e_alloc_failure;
   618→                        }
   619→
   620→                        flags |= flag_next;
   621→                        break;
   622→
   623→                    case 'n':
   624→
   625→                        if ((end - i) < 3 || *(++i) != 'u' || *(++i) != 'l' ||
   626→                            *(++i) != 'l') {
   627→                            goto e_unknown_value;
   628→                        }
   629→
   630→                        if (!new_value(&state, &top, &root, &alloc,
   631→                                       json_null)) {
   632→                            goto e_alloc_failure;
   633→                        }
   634→
   635→                        flags |= flag_next;
   636→                        break;
   637→
   638→                    default:
   639→
   640→                        if (isdigit((uint8_t)b) || b == '-') {
   641→                            if (!new_value(&state, &top, &root, &alloc,
   642→                                           json_integer)) {
   643→                                goto e_alloc_failure;
   644→                            }
   645→
   646→                            if (!state.first_pass) {
   647→                                while (isdigit((uint8_t)b) || b == '+' || b ==
   648→                                       '-'
   649→                                       || b == 'e' || b == 'E' || b == '.') {
   650→                                    if ((++i) == end) {
   651→                                        b = 0;
   652→                                        break;
   653→                                    }
   654→
   655→                                    b = *i;
   656→                                }
   657→
   658→                                flags |= flag_next | flag_reproc;
   659→                                break;
   660→                            }
   661→
   662→                            flags &= ~(flag_num_negative | flag_num_e |
   663→                                       flag_num_e_got_sign |
   664→                                       flag_num_e_negative |
   665→                                       flag_num_zero);
   666→
   667→                            num_digits   = 0;
   668→                            num_fraction = 0;
   669→                            num_e        = 0;
   670→
   671→                            if (b != '-') {
   672→                                flags |= flag_reproc;
   673→                                break;
   674→                            }
   675→
   676→                            flags |= flag_num_negative;
   677→                            continue;
   678→                        } else {
   679→                            sprintf(error,
   680→                                    "%d:%d: Unexpected %c when seeking value",
   681→                                    cur_line, e_off, b);
   682→                            goto e_failed;
   683→                        }
   684→                    }
   685→                }
   686→            } else {
   687→                switch (top->type) {
   688→                case json_object:
   689→
   690→                    switch (b) {
   691→whitespace:
   692→                        continue;
   693→
   694→                    case '"':
   695→
   696→                        if (flags & flag_need_comma) {
   697→                            sprintf(error, "%d:%d: Expected , before \"",
   698→                                    cur_line, e_off);
   699→                            goto e_failed;
   700→                        }
   701→
   702→                        flags |= flag_string;
   703→
   704→                        string        = (json_char *)top->_reserved.object_mem;
   705→                        string_length = 0;
   706→
   707→                        break;
   708→
   709→                    case '}':
   710→
   711→                        flags = (flags & ~flag_need_comma) | flag_next;
   712→                        break;
   713→
   714→                    case ',':
   715→
   716→                        if (flags & flag_need_comma) {
   717→                            flags &= ~flag_need_comma;
   718→                            break;
   719→                        }
   720→
   721→                    default:
   722→
   723→                        sprintf(error, "%d:%d: Unexpected `%c` in object",
   724→                                cur_line, e_off, b);
   725→                        goto e_failed;
   726→                    }
   727→
   728→                    break;
   729→
   730→                case json_integer:
   731→                case json_double:
   732→
   733→                    if (isdigit((uint8_t)b)) {
   734→                        ++num_digits;
   735→
   736→                        if (top->type == json_integer || flags & flag_num_e) {
   737→                            if (!(flags & flag_num_e)) {
   738→                                if (flags & flag_num_zero) {
   739→                                    sprintf(error,
   740→                                            "%d:%d: Unexpected `0` before `%c`",
   741→                                            cur_line, e_off, b);
   742→                                    goto e_failed;
   743→                                }
   744→
   745→                                if (num_digits == 1 && b == '0') {
   746→                                    flags |= flag_num_zero;
   747→                                }
   748→                            } else {
   749→                                flags |= flag_num_e_got_sign;
   750→                                num_e  = (num_e * 10) + (b - '0');
   751→                                continue;
   752→                            }
   753→
   754→                            top->u.integer = (top->u.integer * 10) + (b - '0');
   755→                            continue;
   756→                        }
   757→
   758→                        num_fraction = (num_fraction * 10) + (b - '0');
   759→                        continue;
   760→                    }
   761→
   762→                    if (b == '+' || b == '-') {
   763→                        if ((flags & flag_num_e) &&
   764→                            !(flags & flag_num_e_got_sign)) {
   765→                            flags |= flag_num_e_got_sign;
   766→
   767→                            if (b == '-') {
   768→                                flags |= flag_num_e_negative;
   769→                            }
   770→
   771→                            continue;
   772→                        }
   773→                    } else if (b == '.' && top->type == json_integer) {
   774→                        if (!num_digits) {
   775→                            sprintf(error, "%d:%d: Expected digit before `.`",
   776→                                    cur_line, e_off);
   777→                            goto e_failed;
   778→                        }
   779→
   780→                        top->type  = json_double;
   781→                        top->u.dbl = (double)top->u.integer;
   782→
   783→                        num_digits = 0;
   784→                        continue;
   785→                    }
   786→
   787→                    if (!(flags & flag_num_e)) {
   788→                        if (top->type == json_double) {
   789→                            if (!num_digits) {
   790→                                sprintf(error,
   791→                                        "%d:%d: Expected digit after `.`",
   792→                                        cur_line, e_off);
   793→                                goto e_failed;
   794→                            }
   795→
   796→                            top->u.dbl += ((double)num_fraction) /
   797→                                          (pow(10, (double)num_digits));
   798→                        }
   799→
   800→                        if (b == 'e' || b == 'E') {
   801→                            flags |= flag_num_e;
   802→
   803→                            if (top->type == json_integer) {
   804→                                top->type  = json_double;
   805→                                top->u.dbl = (double)top->u.integer;
   806→                            }
   807→
   808→                            num_digits = 0;
   809→                            flags     &= ~flag_num_zero;
   810→
   811→                            continue;
   812→                        }
   813→                    } else {
   814→                        if (!num_digits) {
   815→                            sprintf(error, "%d:%d: Expected digit after `e`",
   816→                                    cur_line, e_off);
   817→                            goto e_failed;
   818→                        }
   819→
   820→                        top->u.dbl *=
   821→                            pow(10,
   822→                                (double)((flags &
   823→                                         flag_num_e_negative) ? -num_e : num_e));
   824→                    }
   825→
   826→                    if (flags & flag_num_negative) {
   827→                        if (top->type == json_integer) {
   828→                            top->u.integer = -top->u.integer;
   829→                        } else {
   830→                            top->u.dbl = -top->u.dbl;
   831→                        }
   832→                    }
   833→
   834→                    flags |= flag_next | flag_reproc;
   835→                    break;
   836→
   837→                default:
   838→                    break;
   839→                }
   840→            }
   841→
   842→            if (flags & flag_reproc) {
   843→                flags &= ~flag_reproc;
   844→                --i;
   845→            }
   846→
   847→            if (flags & flag_next) {
   848→                flags = (flags & ~flag_next) | flag_need_comma;
   849→
   850→                if (!top->parent) {
   851→                    /* root value done */
   852→
   853→                    flags |= flag_done;
   854→                    continue;
   855→                }
   856→
   857→                if (top->parent->type == json_array) {
   858→                    flags |= flag_seek_value;
   859→                }
   860→
   861→                if (!state.first_pass) {
   862→                    json_value *parent = top->parent;
   863→
   864→                    switch (parent->type) {
   865→                    case json_object:
   866→
   867→                        parent->u.object.values
   868→                        [parent->u.object.length].value = top;
   869→
   870→                        break;
   871→
   872→                    case json_array:
   873→
   874→                        parent->u.array.values
   875→                        [parent->u.array.length] = top;
   876→
   877→                        break;
   878→
   879→                    default:
   880→                        break;
   881→                    }
   882→                }
   883→
   884→                if ((++top->parent->u.array.length) > state.uint_max) {
   885→                    goto e_overflow;
   886→                }
   887→
   888→                top = top->parent;
   889→
   890→                continue;
   891→            }
   892→        }
   893→
   894→        alloc = root;
   895→    }
   896→
   897→    return root;
   898→
   899→e_unknown_value:
   900→
   901→    sprintf(error, "%d:%d: Unknown value", cur_line, e_off);
   902→    goto e_failed;
   903→
   904→e_alloc_failure:
   905→
   906→    strcpy(error, "Memory allocation failure");
   907→    goto e_failed;
   908→
   909→e_overflow:
   910→
   911→    sprintf(error, "%d:%d: Too long (caught overflow)", cur_line, e_off);
   912→    goto e_failed;
   913→
   914→e_failed:
   915→
   916→    if (error_buf) {
   917→        if (*error) {
   918→            strcpy(error_buf, error);
   919→        } else {
   920→            strcpy(error_buf, "Unknown error");
   921→        }
   922→    }
   923→
   924→    if (state.first_pass) {
   925→        alloc = root;
   926→    }
   927→
   928→    while (alloc) {
   929→        top = alloc->_reserved.next_alloc;
   930→        state.settings.mem_free(alloc, state.settings.user_data);
   931→        alloc = top;
   932→    }
   933→
   934→    if (!state.first_pass) {
   935→        json_value_free_ex(&state.settings, root);
   936→    }
   937→
   938→    return 0;
   939→}
   940→
   941→json_value *
   942→json_parse(const json_char *json, size_t length)
   943→{
   944→    json_settings settings = { 0UL, 0, NULL, NULL, NULL };
   945→    return json_parse_ex(&settings, json, length, 0);
   946→}
   947→
   948→void
   949→json_value_free_ex(json_settings *settings, json_value *value)
   950→{
   951→    json_value *cur_value;
   952→
   953→    if (!value) {
   954→        return;
   955→    }
   956→
   957→    value->parent = 0;
   958→
   959→    while (value) {
   960→        switch (value->type) {
   961→        case json_array:
   962→
   963→            if (!value->u.array.length) {
   964→                settings->mem_free(value->u.array.values, settings->user_data);
   965→                break;
   966→            }
   967→
   968→            value = value->u.array.values[--value->u.array.length];
   969→            continue;
   970→
   971→        case json_object:
   972→
   973→            if (!value->u.object.length) {
   974→                settings->mem_free(value->u.object.values, settings->user_data);
   975→                break;
   976→            }
   977→
   978→            value = value->u.object.values[--value->u.object.length].value;
   979→            continue;
   980→
   981→        case json_string:
   982→
   983→            settings->mem_free(value->u.string.ptr, settings->user_data);
   984→            break;
   985→
   986→        default:
   987→            break;
   988→        }
   989→
   990→        cur_value = value;
   991→        value     = value->parent;
   992→        settings->mem_free(cur_value, settings->user_data);
   993→    }
   994→}
   995→
   996→void
   997→json_value_free(json_value *value)
   998→{
   999→    json_settings settings = { 0UL, 0, NULL, NULL, NULL };
  1000→    settings.mem_free = default_free;
  1001→    json_value_free_ex(&settings, value);
  1002→}
